// UI chrome translations.
//
// English is the source of truth. Other locales are filled in by
// scripts/translate-i18n.js (which calls Claude). When you add a new key,
// only set the English value here — re-run the script to populate the rest.
//
// Philosophical content (quiz questions, archetype prototype text, philosopher
// entries) lives elsewhere in mull.html and is currently English-only by design;
// translating that body of material safely requires a careful human pass.

export const LOCALES = ['en', 'es', 'fr', 'pt', 'ru', 'zh', 'ja', 'ko'] as const;
export type Locale = typeof LOCALES[number];

export const LOCALE_LABELS: Record<Locale, { native: string; english: string }> = {
  en: { native: 'English', english: 'English' },
  es: { native: 'Español', english: 'Spanish' },
  fr: { native: 'Français', english: 'French' },
  pt: { native: 'Português', english: 'Portuguese' },
  ru: { native: 'Русский', english: 'Russian' },
  zh: { native: '中文', english: 'Chinese' },
  ja: { native: '日本語', english: 'Japanese' },
  ko: { native: '한국어', english: 'Korean' },
};

// Claude-friendly description for the prompt: "Reply in {LOCALE_FOR_PROMPT[locale]}."
export const LOCALE_FOR_PROMPT: Record<Locale, string> = {
  en: 'English',
  es: 'Spanish (Spanish/European Spanish, natural register)',
  fr: 'French (natural conversational French)',
  pt: 'Brazilian Portuguese (natural register)',
  ru: 'Russian (natural register)',
  zh: 'Simplified Chinese (Mandarin, natural register)',
  ja: 'Japanese (natural register, polite-but-conversational)',
  ko: 'Korean (natural register)',
};

type TranslationMap = Record<string, Partial<Record<Locale, string>>>;

