  "account.first_event": { en: "First event — no shifts yet", es: "Primer evento — aún sin desplazamientos", fr: "Premier événement — aucun déplacement pour l'instant", pt: "Primeiro evento — ainda sem deslocamentos", ru: "Первое событие — смещений пока нет", zh: "第一个事件——尚无位移", ja: "最初のイベント――まだ変動はありません", ko: "첫 번째 사건 — 아직 이동 없음" },
