  "dilemma.to_diary":       { en: "Take this further in the diary →", es: "Continúa esto en el diario →", fr: "Prolonger dans le journal →", pt: "Continuar isso no diário →", ru: "Продолжить в дневнике →", zh: "在日记里继续这个 →", ja: "日記でさらに書く →", ko: "일기에서 더 풀어 보기 →" },
